// components/button.tsx
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"

const buttonVariants = cva(
  [
    "inline-flex items-center justify-center font-medium rounded-md",
    "transition-colors focus-visible:outline-none focus-visible:ring-2",
    "focus-visible:ring-ring focus-visible:ring-offset-2",
    "disabled:pointer-events-none disabled:opacity-50",
  ],
  {
    variants: {
      tone: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        danger: "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        outline: "border border-input bg-background hover:bg-accent",
      },
      size: {
        sm: "h-9 px-3 text-sm",
        md: "h-10 px-4",
        lg: "h-11 px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: { tone: "default", size: "md" },
  }
)

type ButtonProps = React.ButtonHTMLAttributes<HTMLButtonElement> &
  VariantProps<typeof buttonVariants>

export function Button({ tone, size, className, ...props }: ButtonProps) {
  return (
    <button className={cn(buttonVariants({ tone, size }), className)} {...props} />
  )
}

// components/input.tsx
import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"

const inputVariants = cva(
  [
    "w-full rounded-md border bg-background px-3 py-2 text-sm",
    "focus:outline-none focus:ring-2 focus:ring-ring focus:border-transparent",
    "disabled:cursor-not-allowed disabled:opacity-50",
    "placeholder:text-muted-foreground",
  ],
  {
    variants: {
      state: {
        default: "border-input",
        error: "border-destructive focus:ring-destructive",
        success: "border-green-500 focus:ring-green-500",
      },
    },
    defaultVariants: { state: "default" },
  }
)

interface InputProps
  extends React.InputHTMLAttributes<HTMLInputElement>,
    VariantProps<typeof inputVariants> {
  label?: string
  error?: string
  hint?: string
}

export function Input({ label, error, hint, state, className, id, ...props }: InputProps) {
  const inputId = id ?? label?.toLowerCase().replace(/\s+/g, "-")
  return (
    <div className="space-y-1">
      {label && (
        <label htmlFor={inputId} className="block text-sm font-medium text-foreground">
          {label}{props.required && <span className="text-destructive ml-1">*</span>}
        </label>
      )}
      <input
        id={inputId}
        className={cn(inputVariants({ state: error ? "error" : state }), className)}
        aria-invalid={!!error}
        aria-describedby={error ? `${inputId}-error` : hint ? `${inputId}-hint` : undefined}
        {...props}
      />
      {error && <p id={`${inputId}-error`} className="text-sm text-destructive">{error}</p>}
      {hint && !error && <p id={`${inputId}-hint`} className="text-sm text-muted-foreground">{hint}</p>}
    </div>
  )
}

// Simple Card using Tailwind tokens, no cva() needed (no variants)
import { cn } from "@/lib/utils"

function Card({ className, children }: { className?: string; children: React.ReactNode }) {
  return (
    <div className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)}>
      {children}
    </div>
  )
}

function CardHeader({ className, children }: { className?: string; children: React.ReactNode }) {
  return <div className={cn("flex flex-col space-y-1.5 p-6", className)}>{children}</div>
}

function CardContent({ className, children }: { className?: string; children: React.ReactNode }) {
  return <div className={cn("p-6 pt-0", className)}>{children}</div>
}

// Prefer CSS variables (bg-background) over dark: prefix when using shadcn tokens
// Use dark: prefix only for components that do not use CSS variable tokens
function Sidebar({ isOpen }: { isOpen: boolean }) {
  return (
    <aside
      data-open={isOpen}
      className={cn(
        "fixed inset-y-0 left-0 w-64 border-r bg-background",
        // data-* selector instead of conditional class toggling
        "translate-x-0 data-[open=false]:-translate-x-full",
        "transition-transform duration-200 ease-in-out",
      )}
    >
      {/* content */}
    </aside>
  )
}
